from typing import List

class Solution:
    def maximumTripletValue(self, nums: List[int]) -> int:
        # n is at most 100, but we can do it in O(n^3) safely.
        n = len(nums)
        best = 0
        for i in range(n - 2):
            for j in range(i + 1, n - 1):
                diff = nums[i] - nums[j]
                for k in range(j + 1, n):
                    val = diff * nums[k]
                    if val > best:
                        best = val
        return best
